341		{
342			//   |---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|---v---|
343			log("\n");
344			log("    write_json [options] [filename]\n");
345			log("\n");
346			log("Write a JSON netlist of the current design.\n");
347			log("\n");
348			log("    -aig\n");
349			log("        include AIG models for the different gate types\n");
350			log("\n");
351			log("    -compat-int\n");
352			log("        emit 32-bit or smaller fully-defined parameter values directly\n");
353			log("        as JSON numbers (for compatibility with old parsers)\n");
354			log("\n");
355			log("    -selected\n");
356			log("        output only select module\n");
357			log("\n");
358			log("    -noscopeinfo\n");
359			log("        don't include $scopeinfo cells in the output\n");
360			log("\n");
361			log("\n");
362			log("The general syntax of the JSON output created by this command is as follows:\n");
363			log("\n");
364			log("    {\n");
365			log("      \"creator\": \"Yosys <version info>\",\n");
366			log("      \"modules\": {\n");
367			log("        <module_name>: {\n");
368			log("          \"attributes\": {\n");
369			log("            <attribute_name>: <attribute_value>,\n");
370			log("            ...\n");
371			log("          },\n");
372			log("          \"parameter_default_values\": {\n");
373			log("            <parameter_name>: <parameter_value>,\n");
374			log("            ...\n");
375			log("          },\n");
376			log("          \"ports\": {\n");
377			log("            <port_name>: <port_details>,\n");
378			log("            ...\n");
379			log("          },\n");
380			log("          \"cells\": {\n");
381			log("            <cell_name>: <cell_details>,\n");
382			log("            ...\n");
383			log("          },\n");
384			log("          \"memories\": {\n");
385			log("            <memory_name>: <memory_details>,\n");
386			log("            ...\n");
387			log("          },\n");
388			log("          \"netnames\": {\n");
389			log("            <net_name>: <net_details>,\n");
390			log("            ...\n");
391			log("          }\n");
392			log("        }\n");
393			log("      },\n");
394			log("      \"models\": {\n");
395			log("        ...\n");
396			log("      },\n");
397			log("    }\n");
398			log("\n");
399			log("Where <port_details> is:\n");
400			log("\n");
401			log("    {\n");
402			log("      \"direction\": <\"input\" | \"output\" | \"inout\">,\n");
403			log("      \"bits\": <bit_vector>\n");
404			log("      \"offset\": <the lowest bit index in use, if non-0>\n");
405			log("      \"upto\": <1 if the port bit indexing is MSB-first>\n");
406			log("      \"signed\": <1 if the port is signed>\n");
407			log("    }\n");
408			log("\n");
409			log("The \"offset\" and \"upto\" fields are skipped if their value would be 0.\n");
410			log("They don't affect connection semantics, and are only used to preserve original\n");
411			log("HDL bit indexing.\n");
412			log("And <cell_details> is:\n");
413			log("\n");
414			log("    {\n");
